/* Color palette: red (#ff0000), black (#000000), white (#ffffff) */
:root {
  --red: #ff0000;
  --black: #000000;
  --white: #ffffff;
}

* { box-sizing: border-box; }
html, body { height: 100%; }

body {
  margin: 0;
  font-family: -apple-system, BlinkMacSystemFont, Segoe UI, Roboto, Arial, sans-serif;
  color: var(--black);
  background: var(--white);
  line-height: 1.6;
  font-size: 16px;
}

img { max-width: 100%; height: auto; display: block; }

.container {
  width: min(960px, 92%);
  margin: 0 auto;
}

.skip-link {
  position: absolute;
  left: -999px;
  top: auto;
  width: 1px;
  height: 1px;
  overflow: hidden;
}
.skip-link:focus {
  position: static;
  width: auto;
  height: auto;
  padding: 0.5rem 1rem;
  background: var(--black);
  color: var(--white);
  outline: 3px solid var(--red);
}

.hero {
  padding: 3rem 0 2rem;
  border-top: 6px solid var(--red);
  border-bottom: 1px solid var(--black);
}
.hero #hero-title {
  margin: 0 0 0.5rem;
  font-size: clamp(1.8rem, 3.2vw + 1rem, 3rem);
}
.subtitle {
  margin: 0 0 1.25rem;
}

.cta-button {
  display: inline-block;
  padding: 0.6rem 1rem;
  border: 2px solid var(--red);
  background: var(--white);
  color: var(--black);
  text-decoration: none;
  font-weight: 600;
}
.cta-button:focus,
.cta-button:hover {
  background: var(--red);
  color: var(--black); /* Black on red passes contrast for normal text */
}

.main-content {
  padding: 1.5rem 0 2.5rem;
}

.services {
  padding: 0 0 1.5rem;
  border-bottom: 1px solid var(--black);
}
.services h2 {
  margin-top: 0;
}
.service-list {
  padding-left: 1.25rem;
  margin: 0.5rem 0 0;
}
.service-list li { margin-bottom: 0.4rem; }

.contact { padding: 1.5rem 0 0; }
.contact h2 { margin-top: 0; }

form { width: 100%; }
.form-field { margin-bottom: 1rem; }
label { display: inline-block; margin-bottom: 0.4rem; font-weight: 600; }
input, textarea {
  width: 100%;
  padding: 0.6rem 0.75rem;
  border: 2px solid var(--black);
  background: var(--white);
  color: var(--black);
}
input:focus, textarea:focus {
  outline: 3px solid var(--red);
  outline-offset: 2px;
}

.submit-button {
  display: inline-block;
  padding: 0.7rem 1.1rem;
  border: 2px solid var(--black);
  background: var(--black);
  color: var(--white);
  font-weight: 700;
  cursor: pointer;
}
.submit-button:focus,
.submit-button:hover {
  border-color: var(--red);
}

.site-footer {
  padding: 1.25rem 0 2rem;
  border-top: 1px solid var(--black);
}
.site-footer small { color: var(--black); }

/* Responsive refinements */
@media (min-width: 600px) {
  .service-list { columns: 2; column-gap: 2rem; }
}
@media (min-width: 900px) {
  .subtitle { max-width: 60ch; }
}

/* Prevent accidental horizontal scroll due to long words */
body, .container, .main-content { overflow-wrap: anywhere; }

document.addEventListener('DOMContentLoaded', () => {
  const form = document.getElementById('contact-form');
  if (form) {
    form.addEventListener('submit', (e) => {
      e.preventDefault();
      const nameEl = document.getElementById('name');
      const nameVal = nameEl && 'value' in nameEl ? String(nameEl.value).trim() : '';
      alert(`Thank you${nameVal ? ', ' + nameVal : ''}! Your message has been received.`);
      if (typeof form.reset === 'function') form.reset();
      if (nameEl && typeof nameEl.focus === 'function') nameEl.focus();
    });
  }

  const yearEl = document.getElementById('year');
  if (yearEl) {
    yearEl.textContent = String(new Date().getFullYear());
  }
});

{
  "name": "lab-technician-landing",
  "version": "1.0.0",
  "private": true,
  "description": "Minimal single-page landing site for a lab technician.",
  "scripts": {
    "test": "jest"
  },
  "devDependencies": {
    "jest": "^29.7.0"
  },
  "jest": {
    "testEnvironment": "node"
  }
}

const fs = require('fs');
const path = require('path');

describe('index.html structure', () => {
  test('contains hero title', () => {
    const html = fs.readFileSync(path.join(__dirname, '..', 'index.html'), 'utf8');
    expect(html).toMatch(/<h1[^>]*id=["']hero-title["'][^>]*>\s*Professional Lab Technician\s*<\/h1>/i);
  });
});
